from pathlib import Path
import base64
root=Path('/home/user/workspace/impex-tiles')
gen=root/'generated'
def data(name):
    b=(gen/name).read_bytes()
    return 'data:image/webp;base64,'+base64.b64encode(b).decode('ascii')
